import{_ as a,c as m,o as e,b as t}from"./app.c18e3cbe.js";const d='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 12","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 12","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 1.","sans":"\u0935\u093F\u0938\u094D\u092E\u092F\u094B \u092F\u094B\u0917\u092D\u0942\u092E\u093F\u0915\u093E\u0903","trans":"Vismayo yogabh\u016Bmik\u0101\u1E25","tags":"vim-1","date":"2021-02-15T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/1/12/index.md"}',i={},s=t('<div class="stanza"><a href="#s1.12" id="s1.12" class="num">1.12</a><div class="sans"><p>\u0915\u093F\u092E\u0938\u094D\u092F \u092E\u0939\u093E\u092F\u094B\u0917\u093F\u0928\u0903 \u0915\u093E\u0936\u094D\u091A\u093F\u0924\u094D \u0924\u0924\u094D\u0924\u094D\u0935\u093E\u0927\u093F\u0930\u094B\u0939\u092A\u094D\u0930\u0924\u094D\u092F\u093E\u0938\u0928\u094D\u0928\u093E \u092D\u0942\u092E\u093F\u0915\u093E\u0903 \u0938\u0928\u094D\u0924\u093F \u092F\u093E\u092D\u093F\u0938\u094D\u0924\u0924\u094D\u0924\u094D\u0935\u094B\u0930\u094D\u0927\u094D\u0935\u0935\u0930\u094D\u0924\u093F\u0928\u0940 \u092D\u0942\u092E\u093F\u0930\u094D\u0932\u0915\u094D\u0937\u094D\u092F\u0924\u0947\u0964 \u0938\u0928\u094D\u0924\u0940\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u0935\u093F\u0938\u094D\u092E\u092F\u094B \u092F\u094B\u0917\u092D\u0942\u092E\u093F\u0915\u093E\u0903\u0965\u0967\u0968\u0965</strong></p></blockquote><p>\u092F\u0925\u093E \u0938\u093E\u0924\u093F\u0936\u092F\u0935\u0938\u094D\u0924\u0941\u0926\u0930\u094D\u0936\u0928\u0947 \u0915\u0938\u094D\u092F\u091A\u093F\u0926\u094D\u0935\u093F\u0938\u094D\u092E\u092F\u094B \u092D\u0935\u0924\u093F \u0924\u0925\u093E\u0938\u094D\u092F \u092E\u0939\u093E\u092F\u094B\u0917\u093F\u0928\u094B \u0928\u093F\u0924\u094D\u092F\u0902 \u0924\u0924\u094D\u0924\u0926\u094D\u0935\u0947\u0926\u094D\u092F\u093E\u0935\u092D\u093E\u0938\u093E\u092E\u0930\u094D\u0936\u093E\u092D\u094B\u0917\u0947\u0937\u0941 \u0928\u093F\u0903\u0938\u093E\u092E\u093E\u0928\u094D\u092F\u093E\u0924\u093F\u0936\u092F\u0928\u0935\u0928\u0935\u091A\u092E\u0924\u094D\u0915\u093E\u0930\u091A\u093F\u0926\u094D\u0918\u0928\u0938\u094D\u0935\u093E\u0924\u094D\u092E\u093E\u0935\u0947\u0936\u0935\u0936\u093E\u0924\u094D\u0938\u094D\u092E\u0947\u0930\u0938\u094D\u092E\u0947\u0930\u0938\u094D\u0924\u093F\u092E\u093F\u0924\u0935\u093F\u0915\u0938\u093F\u0924\u0938\u092E\u0938\u094D\u0924\u0915\u0930\u0923\u091A\u0915\u094D\u0930\u0938\u094D\u092F \u092F\u094B \u0935\u093F\u0938\u094D\u092E\u092F\u094B\u093D\u0928\u0935\u091A\u094D\u091B\u093F\u0928\u094D\u0928\u093E\u0928\u0928\u094D\u0926\u0947 \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0928\u094D\u092F\u092A\u0930\u093F\u0924\u0943\u092A\u094D\u0924\u0924\u094D\u0935\u0947\u0928 \u092E\u0941\u0939\u0941\u0930\u094D\u092E\u0941\u0939\u0941\u0930\u093E\u0936\u094D\u091A\u0930\u094D\u092F\u093E\u092F\u092E\u093E\u0923\u0924\u093E \u0924\u093E \u090F\u0935 \u092F\u094B\u0917\u0938\u094D\u092F \u092A\u0930\u0924\u0924\u094D\u0924\u094D\u0935\u0948\u0915\u094D\u092F\u0938\u094D\u092F \u0938\u092E\u094D\u092C\u0928\u094D\u0927\u093F\u0928\u094D\u092F\u094B \u092D\u0942\u092E\u093F\u0915\u093E\u0938\u094D\u0924\u0926\u0927\u094D\u092F\u093E\u0930\u094B\u0939\u0935\u093F\u0936\u094D\u0930\u093E\u0928\u094D\u0924\u093F\u0938\u0942\u091A\u093F\u0915\u093E\u0903 \u092A\u0930\u093F\u092E\u093F\u0924\u093E \u092D\u0942\u092E\u092F\u094B \u0928 \u0924\u0941 \u0915\u0928\u094D\u0926\u092C\u093F\u0928\u094D\u0926\u094D\u0935\u093E\u0926\u094D\u092F\u0928\u0941\u092D\u0935\u0935\u0943\u0924\u094D\u0924\u092F\u0903\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0915\u0941\u0932\u092F\u0941\u0915\u094D\u0924\u094C</p><blockquote><p>\u0906\u0924\u094D\u092E\u093E \u091A\u0948\u0935\u093E\u0924\u094D\u092E\u0928\u093E \u091C\u094D\u091E\u093E\u0924\u094B \u092F\u0926\u093E \u092D\u0935\u0924\u093F \u0938\u093E\u0927\u0915\u0948\u0903 \u0924\u0926\u093E \u0935\u093F\u0938\u094D\u092E\u092F\u092E\u093E\u0924\u094D\u092E\u093E \u0935\u0948 \u0906\u0924\u094D\u092E\u0928\u094D\u092F\u0947\u0935 \u092A\u094D\u0930\u092A\u0936\u094D\u092F\u0924\u093F\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u090F\u0924\u091A\u094D\u091A</p><blockquote><p>\u0924\u092E\u0927\u093F\u0937\u094D\u0920\u093E\u0924\u0943\u092D\u093E\u0935\u0947\u0928 \u0938\u094D\u0935\u092D\u093E\u0935\u092E\u0935\u0932\u094B\u0915\u092F\u0928\u094D \u0938\u094D\u092E\u092F\u092E\u093E\u0928 \u0907\u0935\u093E\u0938\u094D\u0924\u0947 \u092F\u0938\u094D\u0924\u0938\u094D\u092F\u0947\u092F\u0902 \u0915\u0941\u0938\u0943\u0924\u093F\u0903 \u0915\u0941\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F \u0915\u093E\u0930\u093F\u0915\u092F\u093E \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0965\u0967\u0968\u0965</p></div><hr><div class="trans"><p>Kimasya mah\u0101yogina\u1E25 k\u0101\u015Bcit tattv\u0101dhirohapraty\u0101sann\u0101 bh\u016Bmik\u0101\u1E25 santi y\u0101bhistattvordhvavartin\u012B bh\u016Bmirlak\u1E63yate| Sant\u012Bty\u0101ha\u2014</p><blockquote><p><strong>Vismayo yogabh\u016Bmik\u0101\u1E25||12||</strong></p></blockquote><p>Yath\u0101 s\u0101ti\u015Bayavastudar\u015Bane kasyacidvismayo bhavati tath\u0101sya mah\u0101yogino nitya\u1E41 tattadvedy\u0101vabh\u0101s\u0101mar\u015B\u0101bhoge\u1E63u ni\u1E25s\u0101m\u0101ny\u0101ti\u015Bayanavanavacamatk\u0101racidghanasv\u0101tm\u0101ve\u015Bava\u015B\u0101tsmerasmerastimitavikasitasamastakara\u1E47acakrasya yo vismayo&#39;navacchinn\u0101nande sv\u0101tmanyaparit\u1E5Bptatvena muhurmuhur\u0101\u015Bcary\u0101yam\u0101\u1E47at\u0101 t\u0101 eva yogasya paratattvaikyasya sambandhinyo bh\u016Bmik\u0101stadadhy\u0101rohavi\u015Br\u0101ntis\u016Bcik\u0101\u1E25 parimit\u0101 bh\u016Bmayo na tu kandabindv\u0101dyanubhavav\u1E5Bttaya\u1E25| Tadukta\u1E41 \u015Br\u012Bkulayuktau</p><blockquote><p>\u0100tm\u0101 caiv\u0101tman\u0101 j\xF1\u0101to yad\u0101 bhavati s\u0101dhakai\u1E25 Tad\u0101 vismayam\u0101tm\u0101 vai \u0101tmanyeva prapa\u015Byati||</p></blockquote><p>iti| Etacca</p><blockquote><p>Tamadhi\u1E63\u1E6Dh\u0101t\u1E5Bbh\u0101vena svabh\u0101vamavalokayan Smayam\u0101na iv\u0101ste yastasyeya\u1E41 kus\u1E5Bti\u1E25 kuta\u1E25||</p></blockquote><p>iti k\u0101rikay\u0101 sa\u1E45g\u1E5Bh\u012Btam||12||</p></div><hr><p>\u0418\u043C\u0435\u044E\u0442\u0441\u044F \u043B\u0438 \u043A\u0430\u043A\u0438\u0435-\u043B\u0438\u0431\u043E \u0441\u0442\u0430\u0434\u0438\u0438 <em>(kim... k\u0101\u015Bcid... bh\u016Bmik\u0101\u1E25 santi)</em>, \u0442\u0435\u0441\u043D\u043E \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0435 <em>(praty\u0101sann\u0101\u1E25)</em> \u0441 \u0432\u043E\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435\u043C <em>(adhiroha)</em> \u044D\u0442\u043E\u0433\u043E <em>(asya)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E <em>(mah\u0101)</em> Yog\u012B <em>(yogina\u1E25)</em> \u043A \u0412\u044B\u0441\u0448\u0435\u043C\u0443 \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0443 <em>(tattva)</em>, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043A\u043E\u0442\u043E\u0440\u044B\u0445 --\u0442.\u0435. \u0441\u0442\u0430\u0434\u0438\u0439-- _(y\u0101bhi\u1E25)_\u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u0439 <em>(\u016Brdhvavartin\u012B)</em> [\u0434\u0443\u0445\u043E\u0432\u043D\u044B\u0439] \u0443\u0440\u043E\u0432\u0435\u043D\u044C <em>(bh\u016Bmi\u1E25)</em> \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043E\u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u043E\u0432\u0430\u043D <em>(lak\u1E63yate)</em>?|</p><p>[\u0413\u043E\u0441\u043F\u043E\u0434\u044C \u015Aiva, \u0430\u0432\u0442\u043E\u0440 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u0432,] \u0441\u043A\u0430\u0437\u0430\u043B <em>(\u0101ha)</em>: &quot;\u042D\u0442\u0438 <em>(santi iti)</em>&quot;\u2014</p><blockquote><p><strong>\u0421\u0442\u0430\u0434\u0438\u0438 <em>(bh\u016Bmik\u0101\u1E25)</em> \u0419\u043E\u0433\u0438 <em>(yoga)</em> [\u044F\u0432\u043B\u044F\u044E\u0442 \u0441\u043E\u0431\u043E\u0439] \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u0435 <em>(vismaya\u1E25)</em>||12||</strong></p></blockquote><p>\u0422\u0430\u043A \u0436\u0435 \u043A\u0430\u043A <em>(yath\u0101)</em> \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E <em>(bhavati)</em> [\u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0435] \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u044F <em>(vismaya\u1E25)</em>, \u043A\u043E\u0433\u0434\u0430 \u043A\u0442\u043E-\u0442\u043E \u0432\u0438\u0434\u0438\u0442 <em>(dar\u015Bane kasyacid)</em> \u0432\u044B\u0441\u0448\u0443\u044E <em>(s\u0101ti\u015Baya)</em> \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(vastu)</em>, \u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em> [\u0438\u043C\u0435\u0435\u0442\u0441\u044F] \u0432\u0441\u0435\u0433\u0434\u0430 <em>(nityam)</em> [\u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0435 \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u044F, \u043A\u043E\u0433\u0434\u0430] \u044D\u0442\u043E\u0442 \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B <em>(asya mah\u0101-yogina\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0441\u043F\u043E\u043A\u043E\u0439\u043D\u044B\u043C <em>(stimita)</em>, \u0443\u043B\u044B\u0431\u0430\u044E\u0449\u0438\u043C\u0441\u044F <em>(smera)</em> [\u0438] \u0440\u0430\u0441\u0446\u0432\u0435\u0442\u0448\u0438\u043C [\u043A\u0430\u043A \u0446\u0432\u0435\u0442\u043E\u043A] <em>(smera)</em>, [\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443] \u0432\u0441\u044F \u0435\u0433\u043E <em>(samasta)</em> \u0433\u0440\u0443\u043F\u043F\u0430 <em>(cakrasya)</em> \u0447\u0443\u0432\u0441\u0442\u0432 <em>(kara\u1E47a)</em> [\u0442\u0435\u043F\u0435\u0440\u044C] \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0430 <em>(vikasita)</em>, [\u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0442] \u0432\u043E\u0441\u0442\u043E\u0440\u0433 --\u0101bhoga-- <em>(\u0101bhoge\u1E63u)</em> , [\u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0439 \u0441] \u043E\u043F\u044B\u0442\u043E\u043C <em>(\u0101mar\u015Ba)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(avabh\u0101sa)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 <em>(tad tad)</em> \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u044B\u0445 --\u0442.\u0435. \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432-- <em>(vedya)</em>. [\u0422\u0430\u043A\u0430\u044F \u0433\u0440\u0443\u043F\u043F\u0430 \u0447\u0443\u0432\u0441\u0442\u0432 \u0431\u044B\u043B\u0430 \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0430] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(va\u015B\u0101t)</em> \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F <em>(\u0101ve\u015Ba)</em> \u0432 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(sva)</em> \u042F <em>(\u0101tma)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C] \u043C\u0430\u0441\u0441\u0443 <em>(ghana)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em>, [\u043F\u043E\u043B\u043D\u043E\u0433\u043E] \u0432\u0441\u0435\u0433\u0434\u0430 \u043D\u043E\u0432\u043E\u0433\u043E <em>(nava-nava)</em>, \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u0433\u043E \u0432\u0441\u0435 \u0434\u0440\u0443\u0433\u043E\u0435 <em>(ati\u015Baya)</em> [\u0438] \u043D\u0435\u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E\u0433\u043E <em>(ni\u1E25s\u0101m\u0101nya)</em> \u0412\u043E\u0441\u0442\u043E\u0440\u0433\u0430 \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(camatk\u0101ra)</em>. \u042D\u0442\u043E <em>(ya\u1E25)</em> \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u0435 <em>(vismaya\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043D\u0435\u043E\u0431\u044B\u043A\u043D\u043E\u0432\u0435\u043D\u043D\u044B\u043C <em>(\u0101\u015Bcary\u0101yam\u0101\u1E47at\u0101)</em> \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430 <em>(muhurmuhur)</em>. [\u042D\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F Yog\u012B] \u0432 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C <em>(sva)</em> \u042F <em>(\u0101tmani)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u0433\u043E <em>(anavacchinna)</em> \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(\u0101nande)</em>, \u0438 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u044E\u0449\u0435\u0435\u0441\u044F \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435\u043C \u043F\u043E\u043B\u043D\u043E\u0433\u043E \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F <em>(aparit\u1E5Bptatvena)</em> -- Yog\u012B \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u044D\u0442\u0438\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u044F, \u0442.\u0435. \u043E\u043D \u0436\u0435\u043B\u0430\u0435\u0442 \u0435\u0433\u043E \u0431\u043E\u043B\u044C\u0448\u0435 \u0438 \u0431\u043E\u043B\u044C\u0448\u0435--. \u042D\u0442\u0438 <em>(t\u0101\u1E25 eva)</em> \u0441\u0442\u0430\u0434\u0438\u0438 <em>(bh\u016Bmik\u0101\u1E25)</em> \u0441\u0432\u044F\u0437\u0430\u043D\u044B <em>(sambandhinya\u1E25)</em> \u0441 \u0419\u043E\u0433\u043E\u0439 <em>(yogasya)</em>, [\u0438\u043B\u0438] \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E\u043C <em>(aikyasya)</em> \u0441 \u0412\u044B\u0441\u0448\u0438\u043C <em>(para)</em> \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u043C <em>(tattva)</em> --\u0442.\u0435. \u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u042F--. [\u0422\u0430\u043A\u0438\u0435] \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0435 <em>(parimit\u0101\u1E25)</em> \u044D\u0442\u0430\u043F\u044B, \u0438\u043B\u0438 \u0441\u0442\u0430\u0434\u0438\u0438 <em>(bh\u016Bmaya\u1E25)</em> \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442 <em>(s\u016Bcik\u0101\u1E25)</em> \u043F\u043E\u043A\u043E\u0439 [\u044D\u0442\u043E\u0433\u043E Yog\u012B] <em>(vi\u015Br\u0101nti)</em> \u0432 [\u0435\u0433\u043E] \u0432\u043E\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0438 <em>(adhy\u0101roha)</em> \u043A \u042D\u0442\u043E\u043C\u0443--\u0412\u044B\u0441\u0448\u0435\u043C\u0443 \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0443-- <em>(tad)</em>, \u0430 \u043D\u0435 <em>(na tu)</em> \u0443\u0441\u043B\u043E\u0432\u0438\u044F <em>(v\u1E5Bttaya\u1E25)</em> \u043E\u043F\u044B\u0442\u0430 <em>(anubhava)</em>, [\u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0435\u0433\u043E\u0441\u044F \u043A] Kanda <em>(kanda)</em>, Bindu <em>(bindu)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em><sup>1</sup>|</p><p>\u0422\u0430\u043A <em>(tad)</em> \u0431\u044B\u043B\u043E [\u0442\u0430\u043A\u0436\u0435] \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u0439 <em>(\u015Br\u012B)</em> Kulayukti <em>(kulayuktau)</em>:</p><blockquote><p>&quot;\u0418 <em>(ca eva)</em> \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> &#39;\u042F&#39; <em>(\u0101tm\u0101)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(bhavati)</em> \u043F\u043E\u0437\u043D\u0430\u043D\u043D\u044B\u043C <em>(j\xF1\u0101ta\u1E25)</em> \u0441\u0430\u0434\u0445\u0430\u043A\u0430\u043C\u0438 <em>(s\u0101dhakai\u1E25)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C [\u044D\u0442\u043E\u0433\u043E \u0441\u0430\u043C\u043E\u0433\u043E] &#39;\u042F&#39; <em>(\u0101tman\u0101)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>&#39;\u042F&#39; <em>(\u0101tm\u0101)</em> \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442 <em>(prapa\u015Byati)</em> \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u0435 <em>(vismayam)</em> \u0432 \u041D\u0435\u043C \u0421\u0430\u043C\u043E\u043C <em>(\u0101tmani)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E <em>(vai... eva... iti)</em>&quot;||</p></blockquote><p>\u042D\u0442\u0430 [\u0436\u0435 \u0441\u0430\u043C\u0430\u044F \u0438\u0441\u0442\u0438\u043D\u0430] <em>(etad ca)</em> \u0431\u044B\u043B\u0430 \u0440\u0435\u0437\u044E\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u0430 <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u043C] \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u043C <em>(k\u0101rikay\u0101)</em> [Spandak\u0101rik\u0101-s]:</p><blockquote><p>&quot;\u041A\u0430\u043A <em>(kutas)</em> [\u043C\u043E\u0436\u0435\u0442] \u044D\u0442\u043E\u0442 <em>(iyam)</em> \u043E\u0442\u0432\u0440\u0430\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439 <em>(ku)</em> \u043F\u0443\u0442\u044C \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u0438 <em>(s\u1E5Bti\u1E25)</em> [\u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0442\u044C\u0441\u044F] \u0442\u0435\u043C <em>(tasya)</em>, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442, \u0438\u043B\u0438 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F <em>(\u0101ste)</em> \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u043D\u044B\u043C <em>(smayam\u0101na\u1E25)</em>, \u0442\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u0442\u044C <em>(iva)</em>, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F <em>(avalokayan)</em> \u044D\u0442\u0443 <em>(tam)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443, [\u0438\u043B\u0438 Spanda] <em>(sva-bh\u0101vam)</em>, \u043A\u0430\u043A <em>(bh\u0101vena)</em> \u0443\u043F\u0440\u0430\u0432\u0438\u0442\u0435\u043B\u044F [\u0432\u0441\u0435\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439] <em>(adhi\u1E63\u1E6Dh\u0101t\u1E5B... iti)</em>?&quot;| [\u0421\u043C. Spandak\u0101rik\u0101-s I, 11]</p></blockquote><p>||12||</p><hr><ol><li>\u0425\u043E\u0442\u044F \u0442\u0435\u0440\u043C\u0438\u043D\u044B Kanda \u0438 Bindu \u043E\u0431\u044B\u0447\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0442 &quot;\u044F\u0439\u0446\u0435\u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0439 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A \u0432\u0441\u0435\u0445 n\u0101\u1E0D\u012B-s, \u0438\u043B\u0438 \u043A\u0430\u043D\u0430\u043B\u043E\u0432 \u0432 \u0442\u043E\u043D\u043A\u043E\u043C \u0442\u0435\u043B\u0435&quot; \u0438 &quot;\u0442\u043E\u0447\u043A\u0443, \u0441\u0438\u043C\u0432\u043E\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0449\u0443\u044E \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E --\u0442.\u0435. \u015Aiva--&quot; \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u044D\u0442\u0438 \u0434\u0432\u0430 \u0442\u0435\u0440\u043C\u0438\u043D\u0430 \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0442 M\u016Bl\u0101dh\u0101ra \u0438 \u0100j\xF1\u0101 (\u0445\u043E\u0440\u043E\u0448\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0435 \u0447\u0430\u043A\u0440\u044B (cakra-s), \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u044B\u0435 \u0432 \u0442\u043E\u043D\u043A\u043E\u043C \u0442\u0435\u043B\u0435).</li></ol></div>',1),o=[s];function n(y,v,r,h,p,k){return e(),m("div",null,o)}var c=a(i,[["render",n]]);export{d as __pageData,c as default};
